-- 0021_bias_examples_mitigations.sql
-- Fixes the cognitive-bias-simulator preview/query and fills the content the
-- product advertises ("worked examples, mitigations") but never shipped.
--
-- ROOT-CAUSE (preview 500): previewBiases()/resolveBiasQuery() are the only code
-- paths that SELECT biases.examples / biases.mitigations. If a deployed DB's
-- biases table predates those columns (schema drift), PostgREST 500s that
-- product's preview while every other product works. ADD COLUMN IF NOT EXISTS
-- makes the columns certain to exist; the upsert then populates real content.
-- Idempotent and safe to re-run.

ALTER TABLE biases ADD COLUMN IF NOT EXISTS examples    jsonb NOT NULL DEFAULT '[]';
ALTER TABLE biases ADD COLUMN IF NOT EXISTS mitigations jsonb NOT NULL DEFAULT '[]';

ON CONFLICT (slug) DO UPDATE SET
  name        = EXCLUDED.name,
  description  = EXCLUDED.description,
  source       = EXCLUDED.source,
  examples     = EXCLUDED.examples,
  mitigations  = EXCLUDED.mitigations;
